"use client";

import { useState } from "react";
import { Button, Input } from "@/components/ui";

interface HeroProps {
  headline: string;
  subheadline: string;
  primaryCta: string;
  secondaryCta: string;
  inputPlaceholder: string;
  cursiveAccent?: string;
}

export function Hero({
  headline,
  subheadline,
  primaryCta,
  secondaryCta,
  inputPlaceholder,
  cursiveAccent,
}: HeroProps) {
  const [trackingCode, setTrackingCode] = useState("");

  // Split headline to insert cursive accent
  const renderHeadline = () => {
    if (!cursiveAccent) {
      return headline;
    }

    const parts = headline.split(cursiveAccent);
    if (parts.length === 1) {
      return headline;
    }

    return (
      <>
        {parts[0]}
        <span className="font-serif text-primary">{cursiveAccent}</span>
        {parts[1]}
      </>
    );
  };

  const handleTrack = () => {
    if (trackingCode.trim()) {
      // Placeholder for tracking functionality
      console.log("Tracking:", trackingCode);
    }
  };

  return (
    <section
      id="hero"
      className="relative min-h-screen flex items-center justify-center overflow-hidden pt-24 pb-16 px-4"
    >
      {/* Background Blobs */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div
          className="absolute -top-32 -left-32 w-96 h-96 bg-accent rounded-full blur-3xl opacity-60 animate-float"
          aria-hidden="true"
        />
        <div
          className="absolute -bottom-32 -right-32 w-96 h-96 bg-secondary rounded-full blur-3xl opacity-60 animate-float-delayed"
          aria-hidden="true"
        />
      </div>

      {/* Content */}
      <div className="relative z-10 max-w-2xl mx-auto text-center">
        <h1 className="text-4xl sm:text-5xl md:text-6xl lg:text-7xl font-semibold tracking-tight text-foreground mb-6 leading-tight">
          {renderHeadline()}
        </h1>

        <p className="text-lg sm:text-xl text-muted-foreground max-w-md mx-auto mb-10">
          {subheadline}
        </p>

        {/* Tracking Input */}
        <div className="max-w-md mx-auto mb-6">
          <div className="flex flex-col sm:flex-row gap-3">
            <div className="flex-1">
              <Input
                type="text"
                placeholder={inputPlaceholder}
                value={trackingCode}
                onChange={(e) => setTrackingCode(e.target.value)}
                onKeyDown={(e) => e.key === "Enter" && handleTrack()}
              />
            </div>
            <Button variant="primary" onClick={handleTrack}>
              {primaryCta}
            </Button>
          </div>
        </div>

        {/* Secondary CTA */}
        <div>
          <Button variant="secondary">
            <a href="#request-pickup">{secondaryCta}</a>
          </Button>
        </div>
      </div>
    </section>
  );
}
